let voltage = Math.floor(Math.random() * (470 - 420 + 1)) + 420;
let current = (Math.random() * (15 - 8) + 8);
let temperature = (Math.random() * (65 - 30) + 30).toFixed(2);
let irradiance = Math.floor(Math.random() * (1000 - 200 + 1)) + 200;
let efficiency = (Math.random() * (98 - 80) + 80).toFixed(2);

let power = (voltage * current).toFixed(2);

msg.payload = {
    timestamp: new Date().toISOString(),
    voltage: voltage,
    current: Number(current),
    temperature: Number(temperature),
    irradiance: irradiance,
    efficiency: Number(efficiency),
    power: Number(power)
};

return msg;

let data = msg.payload;

// Health score
let health = 100;

// Temperature penalty
if (data.temperature > 55) health -= 20;

// Efficiency penalty
if (data.efficiency < 85) health -= 15;

// Irradiance penalty
if (data.irradiance < 300) health -= 10;

// Determine status
let status = "Normal";

let fault = "None";

if (data.temperature > 60)
    fault = "Overheating";

if (data.efficiency < 82)
    fault = "Efficiency Degradation";

if (health < 90)
    status = "Warning";

if (health < 70)
    status = "Critical";

msg.payload = {
    plant_id: "PV_PLANT_001",
    sensor_id: "PV_ARRAY_01",
    timestamp: data.timestamp,

    voltage: data.voltage,
    current: data.current,
    power: data.power,

    temperature: data.temperature,
    irradiance: data.irradiance,
    efficiency: data.efficiency,

    health_score: health,
    status: status,
    fault_type: fault
};

return msg;
